package com.schwab.urlShortener.exception;

public class RateLimitExceededException extends RuntimeException {
    public RateLimitExceededException(String message) {
        super(message);
    }
}

package com.schwab.urlShortener.service;

import com.schwab.urlShortener.exception.RateLimitExceededException;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.time.Clock;
import java.time.Instant;
import java.util.Map;
import java.util.Queue;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ConcurrentLinkedQueue;

@Service
public class RateLimiterService {
    private final Map<String, Queue<Instant>> requestTimestamps = new ConcurrentHashMap<>();
    private final int maxRequestsPerMinute;
    private final Clock clock;

    public RateLimiterService(
            @Value("${app.rate-limit.requests-per-minute:60}") int maxRequestsPerMinute,
            Clock clock) {
        this.maxRequestsPerMinute = maxRequestsPerMinute;
        this.clock = clock;
    }

    public void checkRateLimit(String ipAddress) {
        Instant now = clock.instant();
        Instant oneMinuteAgo = now.minusSeconds(60);

        Queue<Instant> timestamps = requestTimestamps.computeIfAbsent(
                ipAddress,
                k -> new ConcurrentLinkedQueue<>());

        timestamps.removeIf(timestamp -> timestamp.isBefore(oneMinuteAgo));

        if (timestamps.size() >= maxRequestsPerMinute) {
            throw new RateLimitExceededException(
                    "Rate limit exceeded. Maximum " + maxRequestsPerMinute + " requests per minute allowed.");
        }

        timestamps.add(now);
    }
}

package com.schwab.urlShortener.exception;

import org.springframework.http.HttpStatus;
import org.springframework.http.ProblemDetail;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(InvalidUrlException.class)
    public ProblemDetail handleInvalidUrlException(InvalidUrlException ex) {
        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(HttpStatus.BAD_REQUEST, ex.getMessage());
        problemDetail.setTitle("Invalid URL");
        return problemDetail;
    }

    @ExceptionHandler(ShortLinkNotFoundException.class)
    public ProblemDetail handleShortLinkNotFoundException(ShortLinkNotFoundException ex) {
        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(HttpStatus.NOT_FOUND, ex.getMessage());
        problemDetail.setTitle("Short Link Not Found");
        return problemDetail;
    }

    @ExceptionHandler(RateLimitExceededException.class)
    public ProblemDetail handleRateLimitExceededException(RateLimitExceededException ex) {
        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(HttpStatus.TOO_MANY_REQUESTS, ex.getMessage());
        problemDetail.setTitle("Rate Limit Exceeded");
        return problemDetail;
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ProblemDetail handleValidationException(MethodArgumentNotValidException ex) {
        String detail = ex.getBindingResult().getFieldErrors().stream()
                .map(error -> error.getField() + ": " + error.getDefaultMessage())
                .findFirst()
                .orElse("Validation failed");
        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(HttpStatus.BAD_REQUEST, detail);
        problemDetail.setTitle("Validation Error");
        return problemDetail;
    }
}

package com.schwab.urlShortener.service;

import com.schwab.urlShortener.exception.RateLimitExceededException;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.time.Clock;
import java.time.Instant;
import java.time.ZoneId;

import static org.assertj.core.api.Assertions.assertThatThrownBy;
import static org.assertj.core.api.Assertions.assertThatNoException;

class RateLimiterServiceTest {

    private static final String IP_ADDRESS_1 = "192.168.1.1";
    private static final String IP_ADDRESS_2 = "192.168.1.2";
    private static final int RATE_LIMIT = 5;

    private ManualClock clock;
    private RateLimiterService rateLimiterService;

    @BeforeEach
    void setUp() {
        clock = new ManualClock();
        rateLimiterService = new RateLimiterService(RATE_LIMIT, clock);
    }

    @Test
    void checkRateLimit_allowsRequestsWithinLimit() {
        assertThatNoException().isThrownBy(() -> {
            for (int i = 0; i < RATE_LIMIT; i++) {
                rateLimiterService.checkRateLimit(IP_ADDRESS_1);
            }
        });
    }

    @Test
    void checkRateLimit_throwsExceptionWhenLimitExceeded() {
        for (int i = 0; i < RATE_LIMIT; i++) {
            rateLimiterService.checkRateLimit(IP_ADDRESS_1);
        }

        assertThatThrownBy(() -> rateLimiterService.checkRateLimit(IP_ADDRESS_1))
                .isInstanceOf(RateLimitExceededException.class)
                .hasMessageContaining("Rate limit exceeded")
                .hasMessageContaining("5 requests per minute");
    }

    @Test
    void checkRateLimit_tracksDifferentIpsIndependently() {
        for (int i = 0; i < RATE_LIMIT; i++) {
            rateLimiterService.checkRateLimit(IP_ADDRESS_1);
        }

        assertThatNoException().isThrownBy(() -> {
            for (int i = 0; i < RATE_LIMIT; i++) {
                rateLimiterService.checkRateLimit(IP_ADDRESS_2);
            }
        });
    }

    @Test
    void checkRateLimit_allowsRequestsAfterTimeWindowExpires() {
        for (int i = 0; i < RATE_LIMIT; i++) {
            rateLimiterService.checkRateLimit(IP_ADDRESS_1);
        }

        clock.advanceSeconds(61);

        assertThatNoException().isThrownBy(() -> {
            for (int i = 0; i < RATE_LIMIT; i++) {
                rateLimiterService.checkRateLimit(IP_ADDRESS_1);
            }
        });
    }

    @Test
    void checkRateLimit_partiallyExpiredTimestampsAllowPartialRequests() {
        for (int i = 0; i < 3; i++) {
            rateLimiterService.checkRateLimit(IP_ADDRESS_1);
        }

        clock.advanceSeconds(61);

        for (int i = 0; i < 3; i++) {
            rateLimiterService.checkRateLimit(IP_ADDRESS_1);
        }

        assertThatNoException().isThrownBy(() -> {
            rateLimiterService.checkRateLimit(IP_ADDRESS_1);
            rateLimiterService.checkRateLimit(IP_ADDRESS_1);
        });

        assertThatThrownBy(() -> rateLimiterService.checkRateLimit(IP_ADDRESS_1))
                .isInstanceOf(RateLimitExceededException.class);
    }

    @Test
    void checkRateLimit_exactlyAtLimitDoesNotThrow() {
        for (int i = 0; i < RATE_LIMIT - 1; i++) {
            rateLimiterService.checkRateLimit(IP_ADDRESS_1);
        }

        assertThatNoException().isThrownBy(() -> 
            rateLimiterService.checkRateLimit(IP_ADDRESS_1)
        );
    }

    @Test
    void checkRateLimit_cleansUpExpiredTimestampsBeforeCounting() {
        rateLimiterService.checkRateLimit(IP_ADDRESS_1);
        rateLimiterService.checkRateLimit(IP_ADDRESS_1);

        clock.advanceSeconds(61);

        for (int i = 0; i < RATE_LIMIT; i++) {
            rateLimiterService.checkRateLimit(IP_ADDRESS_1);
        }

        assertThatThrownBy(() -> rateLimiterService.checkRateLimit(IP_ADDRESS_1))
                .isInstanceOf(RateLimitExceededException.class);
    }

    private static class ManualClock extends Clock {
        private Instant currentInstant = Instant.parse("2024-01-01T12:00:00Z");

        @Override
        public ZoneId getZone() {
            return ZoneId.of("UTC");
        }

        @Override
        public Clock withZone(ZoneId zone) {
            return this;
        }

        @Override
        public Instant instant() {
            return currentInstant;
        }

        public void advanceSeconds(long seconds) {
            currentInstant = currentInstant.plusSeconds(seconds);
        }
    }
}

package com.schwab.urlShortener.exception;

import org.junit.jupiter.api.Test;
import org.springframework.http.HttpStatus;
import org.springframework.http.ProblemDetail;

import static org.assertj.core.api.Assertions.assertThat;

class GlobalExceptionHandlerTest {

    private final GlobalExceptionHandler handler = new GlobalExceptionHandler();

    @Test
    void handleRateLimitExceededException_returns429Status() {
        RateLimitExceededException exception = new RateLimitExceededException(
                "Rate limit exceeded. Maximum 60 requests per minute allowed.");

        ProblemDetail result = handler.handleRateLimitExceededException(exception);

        assertThat(result.getStatus()).isEqualTo(HttpStatus.TOO_MANY_REQUESTS.value());
    }

    @Test
    void handleRateLimitExceededException_setsCorrectTitle() {
        RateLimitExceededException exception = new RateLimitExceededException(
                "Rate limit exceeded. Maximum 60 requests per minute allowed.");

        ProblemDetail result = handler.handleRateLimitExceededException(exception);

        assertThat(result.getTitle()).isEqualTo("Rate Limit Exceeded");
    }

    @Test
    void handleRateLimitExceededException_includesExceptionMessageInDetail() {
        String expectedMessage = "Rate limit exceeded. Maximum 60 requests per minute allowed.";
        RateLimitExceededException exception = new RateLimitExceededException(expectedMessage);

        ProblemDetail result = handler.handleRateLimitExceededException(exception);

        assertThat(result.getDetail()).isEqualTo(expectedMessage);
    }

    @Test
    void handleRateLimitExceededException_withDifferentMessage_preservesMessage() {
        String customMessage = "Custom rate limit message";
        RateLimitExceededException exception = new RateLimitExceededException(customMessage);

        ProblemDetail result = handler.handleRateLimitExceededException(exception);

        assertThat(result.getDetail()).isEqualTo(customMessage);
        assertThat(result.getTitle()).isEqualTo("Rate Limit Exceeded");
        assertThat(result.getStatus()).isEqualTo(429);
    }
}
